def punishmentNumber(n: int) -> int:
    def can_partition(num_str: str, target: int) -> bool:
        # Helper function to check if we can partition num_str
        # into contiguous substrings that sum to target.
        def backtrack(start: int, current_sum: int) -> bool:
            if start == len(num_str):
                return current_sum == target
            for end in range(start + 1, len(num_str) + 1):
                part = int(num_str[start:end])
                if current_sum + part > target:
                    break
                if backtrack(end, current_sum + part):
                    return True
            return False

        return backtrack(0, 0)

    total = 0
    for i in range(1, n + 1):
        square = i * i
        if can_partition(str(square), i):
            total += square
    return total
